import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt3101.jpg",s="/images/lekt3102.jpg",o="/images/lekt3103.jpg",l="/images/lekt3105.jpg",p="/images/lekt3104.jpg",P=JSON.parse('{"title":"Lektion 31","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion31.md","filePath":"lektionen/lektion31.md"}'),u={name:"lektionen/lektion31.md"};function b(d,e,c,h,m,k){return r(),t("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-31" tabindex="-1">Lektion 31 <a class="header-anchor" href="#lektion-31" aria-label="Permalink to &quot;Lektion 31&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>31.1. Die 7. Präsensklasse (रुधादि = &quot;रुध् u.s.w.&quot;)</li><li>31.2. Wortliste</li><li>31.3. Übung</li></ul><h2 id="_31-1-die-7-prasensklasse-रुधादि-रुध्-u-s-w" tabindex="-1">31.1. Die 7. Präsensklasse (रुधादि = &quot;रुध् u.s.w.&quot;) <a class="header-anchor" href="#_31-1-die-7-prasensklasse-रुधादि-रुध्-u-s-w" aria-label="Permalink to &quot;31.1. Die 7. Präsensklasse (रुधादि = &quot;रुध् u.s.w.&quot;)&quot;">​</a></h2><p>Bildung:</p><p>Vor den auslautenden Konsonanten der tiefstufigen Wurzel wird ein sog. Nasalinfix (-na- bzw. -n-) eingeschoben:</p><ul><li>im starken Stamm: -na-</li><li>im schwachen Stamm: -n-</li></ul><p>Für die Verbindung der Endkonsonanten der Wurzel mit konsonantisch beginnenden Endungen gelten dieselben Regeln wie für die 2. Präsensklasse.</p><p>Beispiele:</p><p>युज् 7U &quot;verbinden, anschirren&quot;</p><blockquote><p>|   |   | Parasmaipada | Ātmanepada</p><p>| | --- | --- | --- | --- | | Indikativ |   |   |   | |   | 3. sg. | युनक्ति<br> yu-na-j + -ti | युङ्क्ते<br> yu + n + j + te<br> (vor Guttural im Wortinnen werden Nasale durch -ṅ- ersetzt) | |   | 3. pl. | युञ्जन्ति<br> yu + n + j-anti | युञ्जते<br> yu + n + j-ate | | Optativ |   |   |   | |   | 3. sg. | युञ्ज्यात्<br> yu + n + j-yā-t | युञ्जीत<br> yu + n + j-ī-ta<br>   | |   | 3. pl. | युञ्ज्युर्<br> yu + n + j-y-ur | युञ्जीरन्<br> yu + n + j-ī-ran | | Partizip Präsens |   | युञ्जन्त्-<br> yu + n + j-ant-<br> fem.: युञ्जती<br> yu + n + j-at-ī |   |</p></blockquote><p>रुध् 7U &quot;stoppen, zum Stillstand bringen&quot;</p><p>|   |   | Parasmaipada | Ātmanepada</p><p>| | --- | --- | --- | --- | | Indikativ |   |   |   | |   | 3. sg. | रुणद्धि<br> ru + na + dh + ti | रुन्द्धे<br> ru-n + dh + te | |   | 3. pl. | रुन्धन्ति<br> ru-n-dh-anti | रुन्धते<br> ru-n-dh-ate | | Optativ |   |   |   | |   | 3. sg. | रुन्ध्यात्<br> ru-n-dh-yā-t | रुन्धीत<br> ru-n-dh-ī-ta | |   | 3. pl. | रुन्ध्युर्<br> ru-n-dh-y-ur | रुन्धीरन्<br> ru-n-dh-ī-ran | | Partizip Präsens |   | रुन्धन्त्-<br> ru-n-dh-ant-<br> रुन्धती<br> ru-n-dh-at-ī |   |</p><p>Bei einigen Wurzeln ist das -n- des schwachen Präsensstamms auch in außerpräsentische Tempora eingedrungen, sodass diese Wurzeln mit infigiertem Nasal angesetzt werden.</p><p>Beispiel:</p><p>भञ्ज्  7P &quot;brechen</p><ul><li>Indikativ Präsens <ul><li>3.sg.P. भनक्ति (bha-na + j + ti)</li><li>3.pl.P. भञ्जन्ति (bha + n + j-anti)</li></ul></li><li>Futur: भङ्क्ष्यति (bha + n + j + sya + ti)</li><li>Passiv: भज्यते (entwerder aus ursprünglicher Wurzel भज् oder aus *bhñj-ya-te)</li><li>PPP: भग्न (evtl. aus *bhñj + na)</li></ul><h2 id="_31-2-wortliste" tabindex="-1">31.2. Wortliste <a class="header-anchor" href="#_31-2-wortliste" aria-label="Permalink to &quot;31.2. Wortliste&quot;">​</a></h2><p>युज् 7U युनक्ति : anschirren, anjochen, anspannen, befestigen ; Ā auch: sich anspannen (= sich anstrengen), sich verbinden mit, sich konzentrieren auf (Lokativ, सप्तमी)</p><blockquote><p>Fut. योक्ष्यति<br> Pass. युज्यते<br> Kaus. योजयति<br> PPP युक्त<br> Inf. योक्तुम्</p><p>davon:</p><p>युग n.: Joch, Paar, Weltzeitalter (es gibt vier Weltzeitalter:</p><blockquote><ol><li>कृत</li><li>त्रेता</li><li>द्वापर</li><li>कलि</li></ol><p>Das कलियुग begann um 3102 v. Chr., dem Jahr des  महाभारत-Krieges. Näheres bei Basham, Wonder S. 323)</p></blockquote><p>योग m.: &quot;Anschirrung, Anspannung&quot;, Anstrengung, Verbindung, Yoga (siehe dazu Basham, Wonder S. 327ff.)</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: योगः<br> [Bildquelle: <a href="http://www.flickr.com/photos/wricontest/294029791/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wricontest/294029791/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>रुध् 7U रुणद्धि : stoppen, zum Stillstand bringen, zurückhalten = einschließen, verdecken</p><blockquote><p>Fut. रोत्स्यति<br> Pass. रुध्यते<br> Kaus. रोधयति<br> PPP रुद्ध<br> Inf. रोद्धुम्</p></blockquote><p>छिद् 7U छिनत्ति : abschneiden</p><blockquote><p>Fut. छेत्स्यति<br> Pass. छिद्यते<br> Kaus. छेदयति<br> PPP छिन्न<br> Inf. छेत्तुम्</p></blockquote><p>भञ्ज्  7P भनक्ति : (etwas) zerbrechen</p><blockquote><p>Fut. भङ्क्ष्यति<br> Pass. भज्यते<br> PPP भग्न</p></blockquote><p>अञ्ज् 7P अनक्ति : salben, beschmieren</p><blockquote><p>Fut. अङ्क्ष्यति । अञ्जिष्यति<br> Pass. अज्यते<br> Kaus. अञ्जयति<br> PPP अक्त<br> Inf. अञ्जितुम् । अङ्क्तुम्</p></blockquote><p>अञ्ज् +  वि 7Ā व्यङ्क्ते : auseinanderschmieren = sich schminken, sich unterschieden machen</p><blockquote><p>PPP व्यक्त : unterschieden, entfaltet</p><p>davon</p><p>व्यञ्जन n.: Unterscheidungsmittel = Schminke, Gewürz, Kennzeichen, Konsonant (das, wodurch die Bedeutungen unterschieden werden)</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: व्यञ्जनम्<br> Vorbereitung zum Kathakali-Tanz = കഥകളി, Kochi = കൊച്ചി<br> [Bildquelle: winchrisabi. -- <a href="http://www.flickr.com/photos/winchrisabi/181399508/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/winchrisabi/181399508/</a>. -- Zugriff am 2008-12-25. --  <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>भिद् 7U भिनत्ति : spalten</p><blockquote><p>Fut. भेत्स्यति<br> Pass. भिद्यते<br> Kaus. भेदयति<br> PPP भिन्न<br> Inf. भेत्तुम्</p></blockquote><p>भुज् 7U भुनक्ति : genießen (z.B. Essen ; &quot;die Erde genießen&quot; = die Erde beherrschen)</p><blockquote><p>Fut. भोक्ष्यति<br> Pass. भुज्यते<br> Kaus. भोजयति<br> PPP भुक्त<br> Inf. भोक्तुम्</p><p>davon</p><p>भोग m.: Genuss, Essen, Lust, Nutzen, Steuer, Abgabe</p></blockquote><p>बन्ध् 9P बध्नाति (!): binden, anbinden</p><blockquote><p>Fut. भन्त्स्यति<br> Pass. बध्यते<br> Kaus. बन्धयति<br> PPP बद्ध<br> Inf. बन्द्धुम्</p><p>davon:</p><p>बन्धन n.: Binden, Fessel</p></blockquote><p>ज्ञा + प्र 9U प्रजानाति : erkennen, verstehen</p><blockquote><p>davon:</p><p>प्रज्ञा f.: Weisheit, Erkenntnis</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: Aus einem प्रज्ञापारमिता-Manuskript<br> [Bildquelle: zeno.org. -- gemeinfrei]</p><p>भू + सम् 1P सम्भवति : entstehen, existieren</p><p>शरीर n.: Leib, Körper</p><h2 id="_31-3-ubung" tabindex="-1">31.3. Übung <a class="header-anchor" href="#_31-3-ubung" aria-label="Permalink to &quot;31.3. Übung&quot;">​</a></h2><p>A) Übersetzen Sie folgende Sätze und lösen Sie die Komposita auf:</p><p>प्रज्ञा दुःखसम्भवं रुन्ध्यादिति बुद्धिमानार्यबुद्धमार्गेण गच्छेत् ॥१॥</p><p>शस्त्राणि शरीरमेव छिन्दन्ति जीवस्तु न म्रियत इति भगव्द्गीतायां भगवतोच्यते ॥२॥</p><p><img src="'+l+'" alt=""><br> Abb.: शस्त्राणि शरीरमेव छिन्दन्ति जीवस्तु न म्रियत इति भगव्द्गीटायां भगवतोच्यते<br> &quot;Tanks of 18th Cavalry (Indian Army) on the move during the 1965 Indo-Pak War.&quot;<br> [Bildquelle: Hari Singh Deora / Wikipedia. -- Public domain]</p><p>बुद्ध्या युक्तो दुःखान्मुच्यते तस्मान्मोक्षमिच्छन्नरो योगेन युञ्जीत ॥३॥</p><p>पुत्रो जातो बन्धनं जातमिति सुगतो मत्वा कुलबन्धनं भिनत्ति । ततो भग्नबन्धो मोक्षनयन्तीं प्रज्ञामाप्तुमर्हति ॥४॥</p><p><img src="'+p+'" alt=""><br> Abb.: राहुलो जातो बन्धनं जातम् (इति गौतमबोधिसत्त्वः)<br> राहुल, der Sohn Buddhas, Laos<br> [Bildquelle: Sacca / Wikipedia. GNU FDLicense]</p><p>समोहः स्वन्नानि च सुरूपाश्च भुङ्क्ते वीतमोहस्त्वन्नं च सम्पन्नरूपशरीरां च न लुभ्यति । स हि लोभं च क्रोधं च रुणद्धि प्रज्ञायां च युङ्क्ते ॥५॥</p><p>B) Bilden Sie zu folgenden Wurzeln der 7. Klasse alle 3. Personen Singular und Plural, P und Ā, des Indikativ und Optativ Präsens:</p><p>१. छिद्</p><p>२. भिद्</p><p>३. भुज्</p><p>४. अञ्ज् (nur P)</p><p>५. भञ्ज् (nur P)</p>',60)])])}const f=n(u,[["render",b]]);export{P as __pageData,f as default};
